head.script:
scwin.sLoUpperLobranCd = null;
scwin.sCurrDate = null;
scwin.gStvWrkIndictNo = "";
scwin.gWrkIndictKndCd = "";
scwin.gWrkPlCd = "";
scwin.gImpExpClsCd = "Y";
scwin.result3CurrentRow = -1;
scwin.ignoreModified = false;

/**
 * event
 * @name onpageload
 * @description
 */
scwin.onpageload = async function () {
    scwin.sCurrDate = $c.date.getServerDateTime("yyyyMMdd");
    scwin.sLoUpperLobranCd = $c.data.getMemInfo("loUpperLobranCd") ?? "";

    const codeOptions = [
        { grpCd: "OP117", compID: "acb_shiftCd" },
        { grpCd: "OP199", compID: "gr_result3:tformWrkImpleKndCd" },
        { grpCd: "OP168", compID: "gr_result3:pchsAdjmStdCd" },
    ];
    $c.data.setCommonCode(codeOptions, scwin.onLoadCommonCode);

    gr_result3.setUserData("gridName", "중기실적");

    await $c.sbm.execute(sbm_retreiveLoBranCMD);
    acb_lobran.setValue(scwin.sLoUpperLobranCd);

    ica_wrkDt.setValue(scwin.sCurrDate);
    acb_lobran.focus();
};

/**
 * method
 * @name onLoadCommonCode
 * @description
 */
scwin.onLoadCommonCode = function () {
    $c.data.dataListFilter(dlt_commonCodeOP199, "fltrCd2 == '1'");
    $c.data.dataListFilter(dlt_commonCodeOP168, "fltrCd2 == '1'");
};

/**
 * method
 * @name f_qeryList
 * @description 조회
 */
scwin.f_qeryList = async function () {
    if (!await $c.gus.cfValidate([ica_wrkDt])) {	// 작업일자
        return;
    }
    $c.sbm.execute(sbm_Retrieve);
};

/**
 * method
 * @name f_cntrList
 * @description 컨테이너조회
 */
scwin.f_cntrList = async function (orderNumber) {
    dma_cntr_Retrieve.set("orderNumber", orderNumber);
    await $c.sbm.execute(sbm_cntr_Retrieve);
    tbx_totalRow2.setValue(ds_sd401.getRowCount());
};

/**
 * method
 * @name f_checkVacationDate
 * @description 작업시간 Validation
 */
scwin.f_checkVacationDate = async function () {
    const wrkDt = ica_wrkDt.getValue();
    let wrkStMm = null;
    let wrkEndMm = null;
    const allData = ds_result3.getAllFilteredJSON();
    let rowObj = null;
    for (let idx = 0; idx < allData.length; ++idx) {
        rowObj = allData[idx];

        wrkStMm = rowObj.wrkStHh.substring(2, 4);
        if (wrkStMm != "00" && wrkStMm != "30") {
            await $c.win.alert("시간은 30분 단위로 입력 가능합니다.");
            gr_result3.setFocusedCell(idx, "wrkStHh", true);
            return false;
        }

        wrkEndMm = rowObj.wrkEndHh.substring(2, 4);
        if (wrkEndMm != "00" && wrkEndMm != "30") {
            await $c.win.alert("시간은 30분 단위로 입력 가능합니다.");
            gr_result3.setFocusedCell(idx, "wrkEndHh", true);
            return false;
        }

        //입력한 작업시작일자가 조회일자이후인가
        if (wrkDt != rowObj.wrkStDt) {
            await $c.win.alert("작업시작일자는 작업일자 + 1일까지 입력가능합니다.");
            gr_result3.setFocusedCell(idx, "wrkStDt", true);
            return false;
        }

        //작업시작일자가 작업종료일자 이후 인가

        if (rowObj.wrkStDt > rowObj.wrkEndDt) {
            await $c.win.alert("작업시작일시는 작업종료일시 이전이어야 합니다.");
            gr_result3.setFocusedCell(idx, "wrkStDt", true);
            return false;
        }

        if ((rowObj.wrkStDt + rowObj.wrkStHh) >= (rowObj.wrkEndDt + rowObj.wrkEndHh)) {
            await $c.win.alert("작업시작일시는 작업종료일시 이전이어야 합니다.");
            gr_result3.setFocusedCell(idx, "wrkStHh", true);
            return false;
        }

        let diffDay = await scwin.cfDaysBetween(wrkDt, rowObj.wrkEndDt);
        if (diffDay > 1) {
            await $c.win.alert("작업종료일자는 작업일자 + 1일까지 입력가능합니다.");
            gr_result3.setFocusedCell(idx, "wrkEndDt", true);
            return false;
        }
    }

    let sStDt = "";
    let sEndDt = "";
    let tStDt = "";
    let tEndDt = "";
    let dupChk = false;
    let sRowObj = null;
    let tRowObj = null;
    for (let idx = 0; idx < allData.length; ++idx) {
        sRowObj = allData[idx];

        sStDt = sRowObj.wrkStDt + sRowObj.wrkStHh;
        sEndDt = sRowObj.wrkEndDt + sRowObj.wrkEndHh;

        for (let tIdx = idx + 1; tIdx < allData.length; ++tIdx) {
            tRowObj = allData[tIdx];
            if (sRowObj.eqCd == tRowObj.eqCd) {
                dupChk = false;
                tStDt = tRowObj.wrkStDt + tRowObj.wrkStHh;
                tEndDt = tRowObj.wrkEndDt + tRowObj.wrkEndHh;
                if (sStDt >= tStDt && sStDt >= tEndDt) {
                    dupChk = true;
                } else if (sEndDt <= tStDt && sEndDt <= tEndDt) {
                    dupChk = true;
                }

                if (!dupChk) {
                    await $c.win.alert("중기:" + tRowObj.wrkIndictNo + "작업시간이 중복됩니다.");
                    gr_result3.setFocusedCell(idx, "wrkStDt", true);
                    return false;
                }
            }
        }
    }

    return true;
};

/**
 * method
 * @name f_validate
 * @description
 */
scwin.f_validate = async function () {
    if (!await $c.gus.cfValidate([gr_result3])) {
        return false;
    }

    for (let idx = 0; idx < ds_result3.getRowCount(); ++idx) {
        if (ds_result3.getCellData(idx, "tformWrkImpleKndCd") != "") {
            if ((ds_result3.getCellData(idx, "tformEqPchsPcost") == "" || ds_result3.getCellData(idx, "tformEqPchsPcost") == "0")) {
                await $c.win.alert("매입원가를 입력하십시오.");
                gr_result3.setFocusedCell(idx, "tformEqPchsPcost", true);
                return false;
            }
        }

        if (ds_result3.getCellData(idx, "pchsAdjmStdCd") == "H") {
            if (ds_result3.getCellData(idx, "pchsAdptHhCnt") == "0") {
                await $c.win.alert("적용시간을 입력하십시오.");
                gr_result3.setFocusedCell(idx, "pchsAdptHhCnt", true);
                return false;
            }
        } else {
            if (ds_result3.getCellData(idx, "wrkWt") == "0") {
                await $c.win.alert("작업톤수를 입력하십시오.");
                gr_result3.setFocusedCell(idx, "wrkWt", true);
                return false;
            }
        }

        if (ds_result3.getCellData(idx, "copCoClntNm") != "자사") {
            if (ds_result3.getCellData(idx, "gubun") == "") {
                await $c.win.alert("매입원가 계산버튼을 클릭하십시오.");
                gr_result3.setFocusedCell(idx, "pchsPcostCal", true);
                return false;
            }
        }
    }

    if (!await scwin.f_checkVacationDate()) {
        return false;
    }

    return true;
};

/**
 * method
 * @name f_AddRow3
 * @description 행추가
 */
scwin.f_AddRow3 = async function () {
    if (!ds_result1.getRowCount() || !await scwin.f_validate()) {
        return;
    }

    let data = {
        "wrkIndictNo": scwin.gStvWrkIndictNo,
        "wrkIndictClsCd": scwin.gWrkIndictKndCd,
        "wrkPlCd": scwin.gWrkPlCd,
        "impExpClsCd": scwin.gImpExpClsCd,
        "wrkDt": ica_wrkDt.getValue(),
        "wrkStDt": ica_wrkDt.getValue(),
        "wrkEndDt": ica_wrkDt.getValue(),
        "tformEqPchsPcost": "0",
        "pchsAdptHhCnt": "0",
        "wrkWt": "0",
        "pchsPcost": "0",
        "ctrlPchsPcost": "0",
    };
    ds_result3.insertJSON(ds_result3.getRowCount(), [data]);
    gr_result3.setFocusedCell(ds_result3.getRowCount() - 1, gr_result3.getFocusedColumnIndex() ?? 11, false);
};

/**
 * method
 * @name f_AddRow4
 * @description 행추가
 */
scwin.f_AddRow4 = async function () {
    if (!ds_result1.getRowCount() || !ds_result3.getRowCount() || !await scwin.f_validate()) {
        return;
    }

    let rowObj = ds_result3.getRowJSON(gr_result3.getFocusedRowIndex());
    let data = {
        "stvWrkIndictNo": scwin.gStvWrkIndictNo, //작업지시번호;
        "eqCd": rowObj.eqCd, //장비코드;
        "vehclNo": rowObj.vehclNo, //중기 full;
        "impExpClsCd": 'Y', //수출입구분코드;
        "seq": "0",
    };
    ds_result4.insertJSON(ds_result4.getRowCount(), [data]);
    scwin.setResults4Filter();
    gr_result4.setFocusedCell(ds_result4.getRowCount() - 1, "wrkStDt", false);
};

/**
 * method
 * @name f_Save
 * @description 저장
 */
scwin.f_Save = async function () {
    if (!ds_result1.getModifiedIndex().length && !ds_result4.getModifiedIndex().length && !ds_result3.getModifiedIndex().length) {
        await $c.gus.cfAlertMsg("변경된 사항이 없습니다.");
        return;
    }

    if (!await scwin.f_validate()) {
        return;
    }

    let allData = ds_result1.getAllJSON();
    let rowObj = null;
    let idx = 0;
    for (; idx < allData.length; ++idx) {
        rowObj = allData[idx];
        //상태가 삭제가 아니고 Normal이 아닌경우
        if (rowObj.rowStatus != "D" && rowObj.rowStatus != "R") {
            if (rowObj.stvWrkIndictNo == "") {
                await $c.win.alert(rowObj.wrkPlNm + "의 작업계획을 먼저 등록하십시오");
                return;
            }

            if (rowObj.odrNo.substring(1, 3) == "CK") {
                if (rowObj.wrkQty != "" && rowObj.wrkQty != 0 && rowObj.qty != rowObj.wrkQty) {
                    await $c.win.alert("오더번호[" + rowObj.odrNo + "]의 [" + rowObj.wrkStpNm + "]작업단계에 대한 협정물량을 오더물량과 동일하게 입력하십시오.");
                    gr_result1.setFocusedCell(idx, "wrkQty", true);
                    return;
                }

                if (rowObj.wrkWt != "" && rowObj.wrkWt != 0 && rowObj.grossWt != rowObj.wrkWt) {
                    await $c.win.alert("오더번호[" + rowObj.odrNo + "]의 [" + rowObj.wrkStpNm + "]작업단계에 대한 협정물량을 오더물량과 동일하게 입력하십시오.");
                    gr_result1.setFocusedCell(idx, "wrkWt", true);
                    return;
                }

                if (rowObj.wrkCbm != "" && rowObj.wrkCbm != 0 && rowObj.cbm != rowObj.wrkCbm) {
                    await $c.win.alert("오더번호[" + rowObj.odrNo + "]의 [" + rowObj.wrkStpNm + "]작업단계에 대한 협정물량을 오더물량과 동일하게 입력하십시오.");
                    gr_result1.setFocusedCell(idx, "wrkCbm", true);
                    return;
                }
            } else {
                if (rowObj.qty != rowObj.wrkQty || rowObj.grossWt != rowObj.wrkWt || rowObj.cbm != rowObj.wrkCbm) {
                    if (!await $c.win.confirm((idx + 1) + "번째 ROW의 오더물량과 협정물량이 다릅니다. 그래도 저장하시겠습니까?")) {
                        return;
                    }
                }
            }
        }
    }

    let wrkStMm = null;
    let wrkEndMm = null;
    let allResult3Data = ds_result3.getAllFilteredJSON();
    if (ds_result3.getRowStatus(idx) !== undefined && ds_result3.getRowStatus(idx) !== "R") {
        for (let item of allResult3Data) {
            if (item.pchsPcost == 0 || item.pchsPcost == "") {
                await $c.win.alert("매입원가를  입력하십시오");
                return;
            }
            wrkStMm = item.wrkStHh.substring(2, 4);
            if (wrkStMm != "00" && wrkStMm != "30") {
                await $c.win.alert("작업시간은 30분 단위로 입력하십시오");
                return
            }
            wrkEndMm = item.wrkEndHh.substring(2, 4);
            if (wrkEndMm != "00" && wrkEndMm != "30") {
                await $c.win.alert("작업시간은 30분 단위로 입력하십시오");
                return
            }
        }
    }

    let iData = "";
    let jData = "";
    let iwrkStDtm = "";
    let iwrkEndDtm = "";
    let jwrkStDtm = "";
    let jwrkEndDtm = "";
    let jRowObj = null;
    let allResult4Data = ds_result4.getAllFilteredJSON();
    for (let i = 0; i < allResult4Data.length; i++) {
        rowObj = allResult4Data[i];
        iData = rowObj.stvWrkIndictNo + rowObj.eqCd;
        iwrkStDtm = rowObj.wrkStDt + rowObj.wrkStHh;
        iwrkEndDtm = rowObj.wrkEndDt + rowObj.wrkEndHh;
        for (let j = i + 1; j < allResult4Data.length; j++) {
            jRowObj = allResult4Data[j];
            jData = jRowObj.stvWrkIndictNo + jRowObj.eqCd;
            if (iData !== jData) {
                continue;
            }

            //같은 작업장 같은 중기의 경우;
            jwrkStDtm = jRowObj.wrkStDt + jRowObj.wrkStHh;
            jwrkEndDtm = jRowObj.wrkEndDt + jRowObj.wrkEndHh;

            if ((iwrkStDtm < jwrkStDtm && iwrkEndDtm > jwrkStDtm) ||
                (iwrkStDtm >= jwrkStDtm && iwrkEndDtm <= jwrkEndDtm) ||
                (iwrkStDtm < jwrkEndDtm && iwrkEndDtm > jwrkEndDtm)) {
                const msg = `작업지시번호가 [${rowObj.stvWrkIndictNo}]인 중기[${rowObj.vehclNo}]의 \r\n작업시간[${iwrkStDtm} ~ ${iwrkEndDtm}]이 \r\n타 작업시간[${jwrkStDtm} ~ ${jwrkEndDtm}]과 중복됩니다.`;
                await $c.win.alert(msg);
                return;
            }
        }
    }

    // 입력시간 검사 (30분 단위 입력)
    for (let idx = 0; idx < allResult4Data.length; ++idx) {
        rowObj = allResult4Data[idx];
        wrkStMm = rowObj.wrkStHh.substring(2, 4);
        if (wrkStMm != "00" && wrkStMm != "30") {
            await $c.win.alert("작업시간은 30분 단위로 입력하십시오");
            gr_result4.setFocusedCell(idx, "wrkStHh", true);
            return
        }

        wrkEndMm = rowObj.wrkEndHh.substring(2, 4);
        if (wrkEndMm != "00" && wrkEndMm != "30") {
            await $c.win.alert("작업시간은 30분 단위로 입력하십시오");
            gr_result4.setFocusedCell(idx, "wrkEndHh", true);
            return
        }

        if (rowObj.wrkStDt + rowObj.wrkStHh > rowObj.wrkEndDt + rowObj.wrkEndHh) {
            await $c.win.alert("작업종료일자 및 작업종료시간이 작업시작일자 및 작업시작시간보다 작습니다");
            return;
        }
    }

    let mkey = null;
    let totInputHhCnt = null;
    let totInputMintCnt = null;
    let matchExist = null;
    let calcData = null;
    for (let i = 0; i < allResult3Data.length; ++i) {
        rowObj = allResult3Data[i];
        matchExist = false;
        mkey = rowObj.wrkIndictNo + rowObj.eqCd;

        totInputHhCnt = 0;
        totInputMintCnt = 0;
        for (let j = 0; j < allResult4Data.length; ++j) {
            jRowObj = allResult4Data[j];
            //삭제한 자료 제외
            if (jRowObj.rowStatus != "D" && mkey == jRowObj.stvWrkIndictNo + jRowObj.eqCd) {
                matchExist = true;
                calcData = await scwin.f_CalcWrkTime(jRowObj.wrkStDt, jRowObj.wrkEndDt, jRowObj.wrkStHh, jRowObj.wrkEndHh);
                totInputHhCnt += calcData.totInputHhCnt;
                totInputMintCnt += calcData.totInputMintCnt;
            }
        }

        if (!matchExist) { //상세일시가 없으면 자기것으로 계산한다
            calcData = await scwin.f_CalcWrkTime(rowObj.wrkStDt, rowObj.wrkEndDt, rowObj.wrkStHh, rowObj.wrkEndHh);
            totInputHhCnt = calcData.totInputHhCnt;
            totInputMintCnt = calcData.totInputMintCnt;
        }
        ds_result3.setCellData(i, "totInputHhCnt", totInputHhCnt);
        ds_result3.setCellData(i, "totInputMintCnt", totInputMintCnt);
    }

    if (await $c.win.confirm("저장하시겠습니까?")) {
        scwin.ignoreModified = true; //CanRowPosChange 이벤트는 타지 못하게 한다;
        $c.sbm.execute(sbm_Save);
    }
};

/**
* method
* @name cfDaysBetween
* @description
*/
scwin.cfDaysBetween = async function (stDt, endDt) {
    let v_daysBetween = 0;
    if (!$c.date.isDate(stDt)) {
        await $c.win.alert("시작일자는 'YYYYMMDD' 형식이어야 합니다.");
    } else if (!$c.date.isDate(endDt)) {
        await $c.win.alert("종료일자는 'YYYYMMDD' 형식이어야 합니다.");
    } else {
        v_daysBetween = $c.date.diffDate(stDt, endDt);
    }
    return v_daysBetween;
};

/**
 * method
 * @name f_CalcWrkTime
 * @params {String} wrkStDt     시작일자 (포멧: yyyyMMdd)
 * @params {String} wrkStDt     종료일자 (포멧: yyyyMMdd)
 * @params {String} wrkStHh     시작시간 (포멧: HHmm)
 * @params {String} wrkEndHh    종료시간 (포멧: HHmm)
 * @returns {Object}
 *          {Number} totInputHhCnt      시간차이
 *          {Number} totInputMintCnt    분차이
 * @description 작업시간계산
 */
scwin.f_CalcWrkTime = async function (wrkStDt, wrkEndDt, wrkStHh, wrkEndHh) {
    let v_daysBetween = await scwin.cfDaysBetween(wrkStDt, wrkEndDt);
    let v_StHh = $c.num.parseInt(wrkStHh.substring(0, 2));   //시작시간
    let v_StMm = $c.num.parseInt(wrkStHh.substring(2, 4));   //시작분

    let v_EndHh = $c.num.parseInt(wrkEndHh.substring(0, 2)); //종료시간
    let v_EndMm = $c.num.parseInt(wrkEndHh.substring(2, 4)); //종료분

    let v_diff = 0;	//총시간차이
    if (v_daysBetween > 0) {
        --v_daysBetween;

        // 날짜차이*24시간*60분 + (24시간*60분 - 시작시간*60분 + 시작분수) + (종료시간*60분 + 종료분수)
        v_diff = v_daysBetween * 24 * 60 + (24 * 60 - v_StHh * 60 + v_StMm) + (v_EndHh * 60 + v_EndMm);
    } else {
        // 종료시간 - 시작시간
        v_diff = (v_EndHh * 60 + v_EndMm) - (v_StHh * 60 + v_StMm);
    }
    let v_diffHh = $c.num.parseInt(v_diff / 60);    //시간차이
    let v_diffMm = $c.num.parseInt(v_diff % 60);    //분차이

    return {
        "totInputHhCnt": v_diffHh,
        "totInputMintCnt": v_diffMm,
    };
};

/**
 * method
 * @name f_chkOpenCommonPopUp
 * @description 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
 */
scwin.f_chkOpenCommonPopUp = function (inObj, pairObj, disGubun, isCode) {
    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj)) {
        return;
    }

    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    let pVal = $c.gus.cfGetValue(inObj);
    if (isCode == null || isCode == true) {
        // inObj가 코드 필드일 경우 팝업
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'F');
    } else {
        // inObj가 코드명 필드일 경우 팝업
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
    }
};

