/**
 * method
 * @name f_openCommonPopUpGrid
 * @description 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
 */
scwin.f_openCommonPopUpGrid = async function (row, disGubun, pCode, pName, pWinCloseTF = "T") {
    let rtnList = null;  // 공통POP-UP -> 요청화면
    let arrParam = null;
    pCode = pCode.replace(/\s*$/, '');

    switch (disGubun) {
        case 1:	//중기(grid)
            arrParam = new Array();
            arrParam[0] = '';    //assgnLobranCd점소코드
            arrParam[1] = '';		  //eqKndCd중기종류
            arrParam[2] = '';	  //clntCd거래처코드
            arrParam[3] = ica_wrkDt.getValue();		    //usblDt작업계획일지
            arrParam[4] = pCode;		//eqNo
            arrParam[5] = pName;			//차량번호
            arrParam[6] = pWinCloseTF;	//T,F구분
            arrParam[7] = 'T';	//T,F구분

            let opts = {
                id: "op_101_01_12p_popup",
                popupName: "중기조회",
                modal: true,
                type: "browserPopup",  //화면 오픈 타입 ("pageFramePopup", "browserPopup")
                title: "op_101_01_12p pop",  //Layer pop
                width: 1050,
                height: 550,
            };
            rtnList = await $c.win.openPopup("/ui/ds/op/rscconfirm/transrscconfirm/op_101_01_12p.xml", opts, arrParam);
            if (rtnList != null) {
                ds_result3.setCellData(row, "vehclShortCd", rtnList[0]);	//단축코드
                ds_result3.setCellData(row, "vehclNo", rtnList[1]);	//차량FULL코드
                ds_result3.setCellData(row, "eqCd", rtnList[12]);//중기코드
                ds_result3.setCellData(row, "eqKndCd", rtnList[15]);	//중기종류코드
                ds_result3.setCellData(row, "eqNrmCd", rtnList[11]);	//중기규격코드
                ds_result3.setCellData(row, "assgnLobranCd", rtnList[14]);	//중기배정점소코드

                if (rtnList[5] == '자사') {
                    ds_result3.setCellData(row, "loanRateOutbrYn", 0);
                } else {
                    ds_result3.setCellData(row, "loanRateOutbrYn", 1);
                }
            }

            if (ds_result3.getCellData(row, "vehclShortCd") == "") {
                ds_result3.setCellData(row, "copCoClntNo", "");
                ds_result3.setCellData(row, "copCoClntNm", "");
                ds_result3.setCellData(row, "wrkStDt", "");
                ds_result3.setCellData(row, "wrkStHh", "");
                ds_result3.setCellData(row, "wrkEndDt", "");
                ds_result3.setCellData(row, "wrkEndHh", "");
                ds_result3.setCellData(row, "tformWrkImpleKndCd", "");
                ds_result3.setCellData(row, "tformEqPchsPcost", "0");
                ds_result3.setCellData(row, "pchsAdjmStdCd", "");
                ds_result3.setCellData(row, "pchsAdptHhCnt", "0");
                ds_result3.setCellData(row, "wrkWt", "0");
                ds_result3.setCellData(row, "pchsPcost", "0");
                ds_result3.setCellData(row, "pchsPcostCal", "");
                ds_result3.setCellData(row, "ctrlPchsPcost", "0");
            }
            break;

        case 2:	//업체코드(grid)
            scwin.result3CurrentRow = row;
            udc_heavyMachineryClntInfo.cfCommonPopUp(scwin.udc_heavyMachineryClntInfo_popup_callback, pCode, pName, "F", null, null, null, null, null, 450, 500, null, null); // 중기협력업체
            break;

        case 3:	//매입원가 계산(grid)
            await scwin.f_CalcPchsPcost(row);
            break;

        case 4: //매입부서
            scwin.result3CurrentRow = row;
            udc_logisDeptInfo.cfCommonPopUp(scwin.udc_logisDeptInfo_popup_callback
                , pCode
                , pName
                , "T"
                , null
                , null
                , null
                , null
                , ",,,,,,1,"
                , null
                , null
                , null
                , null
                , null
                , null
                , "매입부서,매입부서코드,매입부서");
            break;

        default:
            break;
    }
};

