/**
 * method
 * @name f_CalcPchsPcost
 * @description 매입원가계산
 */
scwin.f_CalcPchsPcost = async function (row) {
    // 필수 입력 체크
    let rowObj = ds_result3.getRowJSON(row);
    if (ds_result3.getRowCount()) {
        if (rowObj.vehclShortCd == "") {
            await $c.win.alert("단축코드는 필수 입력항목입니다.");
            gr_result3.setFocusedCell(row, "vehclShortCd", true);
            return;
        }

        if (rowObj.vehclNo == "") {
            await $c.win.alert("FULL번호는 필수 입력항목입니다.");
            gr_result3.setFocusedCell(row, "vehclNo", true);
            return;
        }

        if (rowObj.copCoClntNo == "") {
            await $c.win.alert("협력업체는 필수 입력항목입니다.");
            gr_result3.setFocusedCell(row, "copCoClntNo", true);
            return;
        }
    }

    let v_clntNo = rowObj.copCoClntNo; //협력업체
    let v_lobranCd = rowObj.assgnLobranCd;//중기배정점소
    // 자사이거나 월대이면 공통요율 사용
    if (ds_result3.getCellData(0, "copCoClntNm") == '자사') {
        v_clntNo = " ";
    }

    // 조회 조건 DataSet에 입력
    dma_searchPchsPcost.setEmptyValue();
    dma_searchPchsPcost.setJSON({
        "lobranCd": v_lobranCd,
        "clntNo": v_clntNo,
        "eqKndCd": rowObj.eqKndCd,
        "eqNrmCd": rowObj.eqNrmCd,
        "wrkUnitCd": rowObj.pchsAdjmStdCd,
        "stDt": rowObj.wrkStDt,
    });

    // 조회 조건1 DataSet에 입력
    dma_searchPchsPcost1.setEmptyValue();
    dma_searchPchsPcost1.setJSON(rowObj);
    ds_pchsPcost.removeAll();
    $c.sbm.execute(sbm_searchPchsPcost);
};

/**
 * method
 * @name f_diffHour
 * @description
 */
scwin.f_diffHour = async function (stDt, stHh, endDt, endHh) {
    let dtConverterHour = (await scwin.cfDaysBetween(stDt, endDt)) * 24;
    let stHhConverterHour = $c.num.parseInt(stHh.substring(0, 2));
    let endHhConverterHour = $c.num.parseInt(endHh.substring(0, 2));

    if (stHh.substring(2, 4) === "30") {
        ++stHhConverterHour;
    }

    if (endHh.substring(2, 4) === "30") {
        ++endHhConverterHour;
    }

    return dtConverterHour + endHhConverterHour - stHhConverterHour;
};

/**
 * method
 * @name cfValidateValue
 * @description
 */
scwin.cfValidateValue = function (valInfo, value) {
    if (valInfo.isTime) {
        if (value.length < 5) {
            value = scwin.sCurrDate + value;
        }
        return $c.date.isDate(value, true);
    }

    let msgInfo = $c.data.getValResultMsg(valInfo, value);
    if (msgInfo.message === "") {
        return true;
    }
    return false;
};

/**
 * event
 * @name sbm_Retrieve_submitdone
 * @description
 */
scwin.sbm_Retrieve_submitdone = async function (e) {
    if (e.responseJSON?.resultDataSet?.length && e.responseJSON.resultDataSet[0].Code == -1) {
        return;
    }

    tbx_totalRow1.setValue(ds_result1.getRowCount());
    //for=ds_result1
    if (!ds_result1.getRowCount()) {
        if (ds_result3.getRowCount()) {
            gr_result3.setFocusedCell(0, "vehclShortCd", false);
        }
        if (ds_result4.getRowCount()) {
            gr_result4.setFocusedCell(0, "vehclNo", false);
        }
        tbx_totalRow3.setValue(ds_result3.getRowCount());
        tbx_totalRow4.setValue(ds_result4.getRowCount());
        await $c.gus.cfAlertMsg("[작업물량] " + MSG_CM_ERR_003);
    } else {
        let rowObj = ds_result1.getRowJSON(0);
        scwin.gStvWrkIndictNo = rowObj.stvWrkIndictNo;
        scwin.gWrkIndictKndCd = rowObj.wrkIndictKndCd;
        scwin.gWrkPlCd = rowObj.wrkPlCd;

        scwin.setResults3Filter(scwin.gStvWrkIndictNo);

        if (ds_result3.getRowCount()) {
            gr_result3.setFocusedCell(0, "vehclShortCd", false);
        }
        if (ds_result4.getRowCount()) {
            gr_result4.setFocusedCell(0, "vehclNo", false);
        }

        let col = (gr_result1.getFocusedColumnIndex() ?? 3);
        if (col < 4) {
            col = 4;
        }
        gr_result1.setFocusedCell(0, col, false);
    }

    scwin.ignoreModified = false;
};

