/**
 * event
 * @name sbm_searchPchsPcost_submitdone
 * @description
 */
scwin.sbm_searchPchsPcost_submitdone = async function (e) {
    if (e.responseJSON?.resultDataSet?.length && e.responseJSON.resultDataSet[0].Code == -1) {
        return;
    }
    let row = gr_result3.getFocusedRowIndex();
    if (ds_pchsPcost.getRowCount()) {
        let data = ds_pchsPcost.getRowJSON(0);
        if (data.pchsPcost == 0 || data.pchsPcost == "") {
            ds_result3.setCellData(row, "gubun", "S");
            await $c.win.alert("해당 요율이 없습니다");
        } else {
            ds_result3.setCellData(row, "pchsPcost", data.pchsPcost);
            ds_result3.setCellData(row, "upr", data.upr);
            ds_result3.setCellData(row, "gubun", "Y");
        }
    } else {
        ds_result3.setCellData(row, "gubun", "S");
        await $c.win.alert("해당 요율이 없습니다");
    }
};

