/**
 * event
 * @name gr_result1_oneditend
 * @description
 */
scwin.gr_result1_oneditend = async function (row, col, newValue) {
    let colid = gr_result1.getColumnID(col);
    const oldValue = ds_result1.getCellData(row, colid);
    if (newValue === oldValue) {
        return;
    }
    switch (colid) {
        case "wrkWt":
            if (!scwin.cfValidateValue({ minNumber: "0" }, newValue)) {
                await $c.gus.cfAlertMsg(MSG_CM_ERR_007, ["중량(톤)"]);
                ds_result1.setCellData(row, colid, oldValue);
            }
            break;
        case "wrkCbm":
            if (!scwin.cfValidateValue({ minNumber: "0" }, newValue)) {
                await $c.gus.cfAlertMsg(MSG_CM_ERR_007, ["CBM"]);
                ds_result1.setCellData(row, colid, oldValue);
            }
            break;
    }
};

/**
