 * @name gr_result1_onafteredit
 * @description
 */
scwin.gr_result1_onafteredit = function (row, col, value) {
    let colid = gr_result1.getColumnID(col);
    switch (colid) {
        case "wrkQty":
        case "wrkWt":
        case "wrkCbm":
            if (value == "" || isNaN(value)) {
                ds_result1.setCellData(row, colid, "0");
            }
            break;
    }
};

/**
 * event
 * @name gr_result3_oneditend
 * @description
 */
scwin.gr_result3_oneditend = async function (row, col, newValue) {
    let colid = gr_result3.getColumnID(col);
    const oldValue = ds_result3.getCellData(row, colid);
    //for=ds_results3
    switch (colid) {
        case "pchsAdjmStdCd":
        case "vehclShortCd":
        case "vehclNo":
        case "copCoClntNo":
        case "copCoClntNm":
            //asis에는 동작하지 않는듯?
            // if (newValue != oldValue) {
            //     // 위의 컬럼 값들이 변경되면 매입금액계산을 다시 해야한다.
            //     ds_result3.setCellData(row, "gubun", "");
            // }
            break;
        case "ctrlPchsPcost":
            if (ds_result3.getCellData(row, "gubun") == "S" && newValue != "" && newValue != "0") {
                //  매입금액계산결과 요율이 없는 경우는 조정금액을 입력하면 매입금액계산한 것과 동일하다.
                ds_result3.setCellData(row, "gubun", "J");
            }
            break;
    }

    //for=gr_results3
    //값변경시 초기화;
    if (newValue != oldValue) {
        switch (colid) {
            case "wrkStDt":
            case "wrkStHh":
            case "wrkEndDt":
            case "wrkEndHh":
                ds_result3.setCellData(row, "tformWrkImpleKndCd", "");
                ds_result3.setCellData(row, "tformEqPchsPcost", "0");
                ds_result3.setCellData(row, "pchsAdjmStdCd", "");
                ds_result3.setCellData(row, "pchsAdptHhCnt", "0");
                ds_result3.setCellData(row, "wrkWt", "0");
                ds_result3.setCellData(row, "pchsPcost", "0");
                ds_result3.setCellData(row, "pchsPcostCal", "");
                ds_result3.setCellData(row, "ctrlPchsPcost", "0");
                break;
        }
    }

    //시간 입력자료검사 및 자동 시간 계산;
    if (colid == "wrkStDt" || colid == "wrkStHh" || colid == "wrkEndDt" || colid == "wrkEndHh") {
        let rowObj = ds_result3.getRowJSON(row);
        rowObj[colid] = newValue;
        if (rowObj.wrkStHh != "") {
            if (rowObj.wrkStHh.substring(2, 4) != "00" && rowObj.wrkStHh.substring(2, 4) != "30") {
                gr_result3.setEventPause("oneditend", true); //이벤트 무한루프 막기위해 이벤트 일시적으로 막음
                await $c.win.alert((row + 1) + "번째의 시간은 30분 단위로 입력 가능합니다.");
                gr_result3.setFocusedCell(row, "wrkStHh", true);
                gr_result3.setEventPause("oneditend", false);
                return;
            }
        }

        if (rowObj.wrkEndHh != "") {
            if (rowObj.wrkEndHh.substring(2, 4) != "00" && rowObj.wrkEndHh.substring(2, 4) != "30") {
                gr_result3.setEventPause("oneditend", true); //이벤트 무한루프 막기위해 이벤트 일시적으로 막음
                await $c.win.alert((row + 1) + "번째의 시간은 30분 단위로 입력 가능합니다.");
                gr_result3.setFocusedCell(row, "wrkEndHh", true);
                gr_result3.setEventPause("oneditend", false);
                return;
            }
        }

        if (rowObj.wrkStDt != "" && rowObj.wrkStHh != "" && rowObj.wrkEndDt != "" && rowObj.wrkEndHh != "") {
            if (!scwin.cfValidateValue({ isDate: true }, rowObj.wrkStDt)) {
                gr_result3.setEventPause("oneditend", true); //이벤트 무한루프 막기위해 이벤트 일시적으로 막음
                await $c.win.alert((row + 1) + " 번째의 작업시작일자");
                gr_result3.setFocusedCell(row, "wrkStDt", true);
                gr_result3.setEventPause("oneditend", false);
                return;
            }

            if (!scwin.cfValidateValue({ isTime: true }, rowObj.wrkStHh)) {
                gr_result3.setEventPause("oneditend", true); //이벤트 무한루프 막기위해 이벤트 일시적으로 막음
                await $c.win.alert((row + 1) + " 번째의 작업시작시간");
                gr_result3.setFocusedCell(row, "wrkStHh", true);
                gr_result3.setEventPause("oneditend", false);
                return;
            }

            if (!scwin.cfValidateValue({ isDate: true }, rowObj.wrkEndDt)) {
                gr_result3.setEventPause("oneditend", true); //이벤트 무한루프 막기위해 이벤트 일시적으로 막음
                await $c.win.alert((row + 1) + " 번째의 작업종료일자");
                gr_result3.setFocusedCell(row, "wrkEndDt", true);
                gr_result3.setEventPause("oneditend", false);
                return;
            }

            if (!scwin.cfValidateValue({ isTime: true }, rowObj.wrkEndHh)) {
                gr_result3.setEventPause("oneditend", true); //이벤트 무한루프 막기위해 이벤트 일시적으로 막음
                await $c.win.alert((row + 1) + " 번째의 작업종료시간");
                gr_result3.setFocusedCell(row, "wrkEndHh", true);
                gr_result3.setEventPause("oneditend", false);
                return;
            }

            if (rowObj.wrkStDt + rowObj.wrkStHh > rowObj.wrkEndDt + rowObj.wrkEndHh) {
                gr_result3.setEventPause("oneditend", true); //이벤트 무한루프 막기위해 이벤트 일시적으로 막음
                await $c.win.alert((row + 1) + " 번째의 작업시작일시는 작업종료일시 이전 이어야 합니다.");
                gr_result3.setFocusedCell(row, "wrkStDt", true);
                gr_result3.setEventPause("oneditend", false);
                return;
            }

            gr_result3.setEventPause("oneditend", true); //이벤트 무한루프 막기위해 이벤트 일시적으로 막음
            //시간계산
            ds_result3.setCellData(row, "pchsAdptHhCnt", await scwin.f_diffHour(rowObj.wrkStDt, rowObj.wrkStHh, rowObj.wrkEndDt, rowObj.wrkEndHh));
            //위 라인 실행시 포커스가 없어진다. 포커스 재설정함
            gr_result3.setFocusedCell(row, gr_result3.getFocusedColumnIndex(), true);
            gr_result3.setEventPause("oneditend", false);
        }
    }
};

/**
 * event
 * @name gr_result3_onviewchange
 * @description
 */
scwin.gr_result3_onviewchange = async function (info) {
    const row = info.rowIndex;
    let newValue = info.newValue;
    switch (info.colId) {
        case "vehclShortCd":
        case "vehclNo":
        case "copCoClntNm":
        case "pchsDeptCd":
        case "pchsDeptNm":
            newValue = newValue.toUpperCase();
            if (newValue != info.oldValue) {	//인서트일때 왼쪽 데이터가 바뀌면 오른쪽 그리드에도 적용해야한다
                switch (info.colId) {
                    case "vehclShortCd":
                        ds_result3.setCellData(row, "vehclNo", "");//중기번호
                        ds_result3.setCellData(row, "vehclShortCd", "");//중기단축코드
                        ds_result3.setCellData(row, "copCoClntNo", "");
                        ds_result3.setCellData(row, "copCoClntNm", "");
                        ds_result3.setCellData(row, "wrkStDt", "");
                        ds_result3.setCellData(row, "wrkStHh", "");
                        ds_result3.setCellData(row, "wrkEndDt", "");
                        ds_result3.setCellData(row, "wrkEndHh", "");
                        ds_result3.setCellData(row, "tformWrkImpleKndCd", "");
                        ds_result3.setCellData(row, "tformEqPchsPcost", "0");
                        ds_result3.setCellData(row, "pchsAdjmStdCd", "");
                        ds_result3.setCellData(row, "pchsAdptHhCnt", "0");
                        ds_result3.setCellData(row, "wrkWt", "0");
                        ds_result3.setCellData(row, "pchsPcost", "0");
                        ds_result3.setCellData(row, "pchsPcostCal", "");
                        ds_result3.setCellData(row, "ctrlPchsPcost", "0");
                        await scwin.f_openCommonPopUpGrid(row, 1, newValue, "");
                        break;
                    case "vehclNo":
                        ds_result3.setCellData(row, "vehclNo", "");//중기번호
                        ds_result3.setCellData(row, "vehclShortCd", "");//중기단축코드
                        await scwin.f_openCommonPopUpGrid(row, 1, "", newValue);
                        break;
                    case "copCoClntNm":
                        ds_result3.setCellData(row, "copCoClntNo", ""); //협력업체코드
                        ds_result3.setCellData(row, "copCoClntNm", ""); //협력업체명
                        await scwin.f_openCommonPopUpGrid(row, 2, "", newValue);
                        break;
                    case "pchsDeptCd":
                        ds_result3.setCellData(row, "pchsDeptCd", ""); //매입부서코드
                        ds_result3.setCellData(row, "pchsDeptNm", ""); //매입부서명
                        await scwin.f_openCommonPopUpGrid(row, 4, newValue, "");
                        break;
                    case "pchsDeptNm":
                        ds_result3.setCellData(row, "pchsDeptCd", ""); //매입부서코드
                        ds_result3.setCellData(row, "pchsDeptNm", ""); //매입부서명
                        await scwin.f_openCommonPopUpGrid(row, 4, "", newValue);
                        break;
                }
            } else {
                ds_result3.setCellData(row, info.colId, newValue);
            }
            break;
    }

    switch (info.colId) {
        case "pchsAdjmStdCd":
            if (ds_result3.getCellData(row, "pchsAdjmStdCd") == "H") {
                ds_result3.setCellData(row, "wrkWt", "0");
            } else if (ds_result3.getCellData(row, "pchsAdjmStdCd") == "W") {
                ds_result3.setCellData(row, "pchsAdptHhCnt", "0");
            } else {
                ds_result3.setCellData(row, "pchsAdptHhCnt", "0");
                ds_result3.setCellData(row, "wrkWt", "0");
            }
            break;

        case "tformWrkImpleKndCd":
            if (ds_result3.getCellData(row, "tformWrkImpleKndCd") == "") {
                ds_result3.setCellData(row, "tformEqPchsPcost", "0");
            }
            break;
    }
};

/**
 * event
 * @name gr_result3_ontextimageclick
 * @description
 */
scwin.gr_result3_ontextimageclick = async function (row, col) {
    let colid = gr_result3.getColumnID(col);
    let gubun;
    let pCode;
    let pName;
    switch (colid) {
        case "vehclShortCd":
            pCode = ds_result3.getCellData(row, "vehclShortCd");
            pName = ds_result3.getCellData(row, "vehclNo");
            ds_result3.setCellData(row, "vehclShortCd", "");
            ds_result3.setCellData(row, "vehclNo", "");
            gubun = 1;
            break;

        case "copCoClntNm":
            pCode = ds_result3.getCellData(row, "copCoClntNo");
            pName = ds_result3.getCellData(row, "copCoClntNm");
            ds_result3.setCellData(row, "copCoClntNo", "");
            ds_result3.setCellData(row, "copCoClntNm", "");
            gubun = 2;
            break;

        case "pchsPcostCal":
            gubun = 3;
            break;

        case "pchsDeptCd":
            pCode = ds_result3.getCellData(row, "pchsDeptCd");
            pName = ds_result3.getCellData(row, "pchsDeptNm");
            ds_result3.setCellData(row, "pchsDeptCd", "");
            ds_result3.setCellData(row, "pchsDeptNm", "");
            gubun = 4;
            break;

        default:
            return;
    }
    await scwin.f_openCommonPopUpGrid(row, gubun, pCode, pName, "F");
};

