/**
 * event
 * @name setResults3Filter
 * @description
 */
scwin.setResults3Filter = function (value) {
    ds_result3.clearFilter();
    if (ds_result3.getRowCount() && value !== "") {
        ds_result3.setColumnFilter({ type: 'row', colIndex: 'wrkIndictNo', key: value, condition: 'and', exactMatch: true });
    }
    tbx_totalRow3.setValue(ds_result3.getRowCount());
};

/**
 * event
 * @name setResults4Filter
 * @description
 */
scwin.setResults4Filter = function () {
    ds_result4.clearFilter();
    let row = gr_result3.getFocusedRowIndex();
    if (row >= 0) {
        let rowObj = ds_result3.getRowJSON(row);
        ds_result4.setColumnFilter({ type: 'row', colIndex: 'stvWrkIndictNo', key: rowObj.wrkIndictNo, condition: 'and', exactMatch: true });
        ds_result4.setColumnFilter({ type: 'row', colIndex: 'eqCd', key: rowObj.eqCd, condition: 'and', exactMatch: true });
    }
    tbx_totalRow4.setValue(ds_result4.getRowCount());
};

/**
 * event
 * @name ds_result1_onbeforerowpositionchange
 * @description CanRowPosChange
 */
scwin.ds_result1_onbeforerowpositionchange = function (info) {
    if (scwin.ignoreModified || info.oldRowIndex === null) {
        return true;
    }

    if (ds_result3.getModifiedIndex().length || ds_result4.getModifiedIndex().length) {
        gr_result1.setEventPause("oncellclick", true); //이벤트 무한루프 막기위해 이벤트 일시적으로 막음
        //이 함수는 async 함수로 선언하면 안된다.
        //await를 피하기 위해 false를 리턴해서 변경을 막고 then에서 변경이 필요하면 변경함
        $c.win.confirm("변경사항이 있습니다. 진행하시겠습니까?").then((rtn) => {
            gr_result1.setEventPause("oncellclick", false);
            if (rtn) {
                scwin.undoAll(ds_result3);
                scwin.undoAll(ds_result4);
                gr_result1.setFocusedCell(info.newRowIndex, gr_result1.getFocusedColumnIndex() ?? 4, true);
            }
        });
        return false;
    }
    return true;
};

/**
 * event
 * @name ds_result3_onbeforerowpositionchange
 * @description CanRowPosChange
 */
scwin.ds_result3_onbeforerowpositionchange = function (info) {
    if (scwin.ignoreModified || info.oldRowIndex === null) {
        return true;
    }

    if (ds_result4.getModifiedIndex().length) {
        //이 함수는 async 함수로 선언하면 안된다.
        //await를 피하기 위해 false를 리턴해서 변경을 막고 then에서 변경이 필요하면 변경함
        $c.win.confirm("변경사항이 있습니다. 진행하시겠습니까?").then((rtn) => {
            if (rtn) {
                scwin.undoAll(ds_result4);
                gr_result3.setFocusedCell(info.newRowIndex, gr_result3.getFocusedColumnIndex() ?? 0, true);
            }
        });
        return false;
    }
    return true;
};

