/**
 * method
 * @name undoAll
 * @description
 */
scwin.undoAll = function (dltObj) {
    for (let idx = dltObj.getRowCount() - 1; idx >= 0; --idx) {
        if (dltObj.getRowStatus(idx) == "C") {
            dltObj.removeRow(idx);
        } else {
            dltObj.undoRow(idx);
        }
    }
};

/**
 * method
 * @name deleteMarked
 * @description
 */
scwin.deleteMarked = function (grdObj, dltObj) {
    let selected = grdObj.getAllFocusedRowIndex();
    selected.sort();
    selected.reverse();
    for (let idx of selected) {
        if (dltObj.getRowStatus(idx) == "C") {
            dltObj.removeRow(idx);
        } else {
            dltObj.deleteRow(idx);
        }
    }
};

/**
 * method
 * @name undoMarked
 * @description
 */
scwin.undoMarked = function (grdObj, dltObj) {
    let selected = grdObj.getAllFocusedRowIndex();
    selected.sort();
    selected.reverse();
    for (let idx of selected) {
        if (dltObj.getRowStatus(idx) == "C") {
            dltObj.removeRow(idx);
        } else {
            dltObj.undoRow(idx);
        }
    }
};

/**
 * method
 * @name cancelRows1
 * @description
 */
scwin.cancelRows1 = function () {
    scwin.undoMarked(gr_result1, ds_result1);
};

/**
 * method
 * @name cancelRows3
 * @description
 */
scwin.cancelRows3 = function () {
    let row = gr_result3.getFocusedRowIndex();
    scwin.undoMarked(gr_result3, ds_result3);
    let rowCnt = ds_result3.getRowCount();
    if (row >= rowCnt) {
        row = 0;
    }
    if (rowCnt) {
        gr_result3.setFocusedCell(row, gr_result3.getFocusedColumnIndex() ?? 11, false);
    }
};

